import jsPDF from 'jspdf'

const SIMBA_LOGO_BASE64 = 'data:image/png;base64,'
const C = {
  primary: [37, 99, 235],
  primaryLight: [219, 234, 254],
  emerald: [16, 185, 129],
  emeraldLight: [209, 250, 229],
  rose: [244, 63, 94],
  roseLight: [255, 228, 230],
  amber: [245, 158, 11],
  amberLight: [254, 243, 199],
  purple: [139, 92, 246],
  purpleLight: [237, 233, 254],
  gray: [107, 114, 128],
  lightGray: [248, 250, 252],
  midGray: [226, 232, 240],
  darkGray: [15, 23, 42],
  white: [255, 255, 255],
  slate: [51, 65, 85],
}

const REASON_COLORS = {
  'Terjual': [16, 185, 129],
  'Rusak': [249, 115, 22],
  'Kadaluarsa': [244, 63, 94],
  'Retur': [59, 130, 246],
  'Hilang': [139, 92, 246],
  'Lainnya': [107, 114, 128],
}

function rp(n) { return 'Rp ' + Number(n || 0).toLocaleString('id-ID') }
function fdate(str, opts = { day: 'numeric', month: 'long', year: 'numeric' }) {
  if (!str) return '-'
  return new Date(str).toLocaleDateString('id-ID', opts)
}
function fshort(str) {
  if (!str) return '-'
  return new Date(str).toLocaleDateString('id-ID', { day: 'numeric', month: 'short' })
}


export async function exportLaporanPDF({ products, stockIn, stockOut, dateFrom, dateTo, preset, chartLineImg }) {
  const doc = new jsPDF('p', 'mm', 'a4')
  const W = 210, H = 297, M = 15, CW = W - M * 2
  let y = 0
  let pageNum = 1

  const totalProducts = products.length
  const totalStockValue = products.reduce((s, p) => s + (p.stock * p.price), 0)
  const totalInQty = stockIn.reduce((s, i) => s + i.quantity, 0)
  const totalInValue = stockIn.reduce((s, i) => s + (i.quantity * (i.buy_price || 0)), 0)
  const totalOutQty = stockOut.reduce((s, o) => s + o.quantity, 0)
  const totalOutValue = stockOut.reduce((s, o) => s + (o.quantity * o.price_at_time), 0)
  const estimasi = totalOutValue - totalInValue

  const topMap = {}
  stockOut.forEach(o => {
    const k = o.product_id
    if (!topMap[k]) topMap[k] = { name: o.products?.name || '-', qty: 0, value: 0 }
    topMap[k].qty += o.quantity; topMap[k].value += o.quantity * o.price_at_time
  })
  const topProducts = Object.values(topMap).sort((a, b) => b.qty - a.qty).slice(0, 5)
  const totalOutAll = topProducts.reduce((s, p) => s + p.qty, 0)

  const reasonMap = {}
  stockOut.forEach(o => {
    const r = o.reason || 'Lainnya'
    if (!reasonMap[r]) reasonMap[r] = { qty: 0, value: 0 }
    reasonMap[r].qty += o.quantity; reasonMap[r].value += o.quantity * o.price_at_time
  })
  const reasonSummary = Object.entries(reasonMap)
    .map(([reason, data]) => ({ reason, ...data, pct: totalOutQty ? ((data.qty / totalOutQty) * 100).toFixed(1) : 0 }))
    .sort((a, b) => b.qty - a.qty)

  const catMap = {}
  stockOut.forEach(o => {
    const c = o.products?.category || 'Lainnya'
    if (!catMap[c]) catMap[c] = 0; catMap[c] += o.quantity
  })
  const topCat = Object.entries(catMap).sort((a, b) => b[1] - a[1])[0]
  const topProduct = topProducts[0]
  const topLoss = reasonSummary.find(r => r.reason === 'Kadaluarsa' || r.reason === 'Rusak')

  const combined = [
    ...stockIn.map(i => ({ type: 'masuk', name: i.products?.name || '-', unit: i.products?.unit || '', qty: i.quantity, price: i.buy_price || 0, keterangan: i.note || i.supplier || '-', created_at: i.created_at })),
    ...stockOut.map(o => ({ type: 'keluar', name: o.products?.name || '-', unit: o.products?.unit || '', qty: o.quantity, price: o.price_at_time, keterangan: o.reason || o.note || '-', created_at: o.created_at }))
  ].sort((a, b) => new Date(b.created_at) - new Date(a.created_at)).slice(0, 15)

  const periodLabel = dateFrom && dateTo
    ? `${fdate(dateFrom)} - ${fdate(dateTo)}`
    : preset === 'today' ? fdate(new Date().toISOString())
    : preset === 'week' ? 'Minggu Ini'
    : preset === 'month' ? fdate(new Date().toISOString(), { month: 'long', year: 'numeric' })
    : preset === 'year' ? new Date().getFullYear().toString()
    : fdate(new Date().toISOString(), { month: 'long', year: 'numeric' })

  function sf(size, style = 'normal', color = C.darkGray) {
    doc.setFontSize(size); doc.setFont('helvetica', style); doc.setTextColor(...color)
  }
  function dr(x, fy, w, h, color, radius = 0, style = 'F') {
    doc.setFillColor(...color)
    if (radius > 0) doc.roundedRect(x, fy, w, h, radius, radius, style)
    else doc.rect(x, fy, w, h, style)
  }
  function db(x, fy, w, h, color, lw = 0.3, radius = 0) {
    doc.setDrawColor(...color); doc.setLineWidth(lw)
    if (radius > 0) doc.roundedRect(x, fy, w, h, radius, radius, 'S')
    else doc.rect(x, fy, w, h, 'S')
  }
  function line(x1, y1, x2, y2, color = C.midGray, lw = 0.3) {
    doc.setDrawColor(...color); doc.setLineWidth(lw)
    doc.line(x1, y1, x2, y2)
  }

  function footer() {
    line(M, H - 11, W - M, H - 11, C.midGray, 0.4)
    sf(7.5, 'normal', C.gray)
    doc.text('Generated by SIMBA', M, H - 6)
    doc.text(`Halaman ${pageNum}`, W / 2, H - 6, { align: 'center' })
    doc.text(fdate(new Date().toISOString()), W - M, H - 6, { align: 'right' })
  }

  function check(need) {
    if (y + need > H - 14) {
      footer(); doc.addPage(); pageNum++; y = M
    }
  }

  function sectionTitle(title) {
    check(16); y += 3
    dr(M, y + 1, 3, 8, C.primary, 1.5)
    sf(10.5, 'bold', C.darkGray)
    doc.text(title, M + 6, y + 7)
    y += 14
  }

  function tableHeader(cols) {
    dr(M, y, CW, 8, C.lightGray)
    db(M, y, CW, 8, C.midGray, 0.25)
    cols.forEach(col => {
      sf(7, 'bold', C.gray)
      doc.text(col.label, M + col.x, y + 5.5)
    })
    y += 8
  }

  // ===== HEADER =====
  dr(0, 0, W, 40, C.primary)

  // Decorative circles
  doc.setFillColor(...C.primary.map(v => Math.min(255, v + 25)))
  doc.circle(W + 5, -5, 45, 'F')
  doc.circle(W - 35, + 3, 15, 'F')

  doc.addImage(SIMBA_LOGO_BASE64, 'PNG', M, 6, 76, 28)

  // Period card
  const pBW = 65, pBX = W - M - pBW
  doc.setDrawColor(255, 255, 255); doc.setLineWidth(0.5)
  doc.roundedRect(pBX, 12, pBW, 18, 3, 3, 'S')
  sf(7, 'normal', [199, 218, 252])
  doc.text('Periode:', pBX + 5, 18)
  sf(9, 'bold', C.white)
  doc.text(periodLabel, pBX + 5, 24)
  sf(6.5, 'normal', [199, 218, 252])
  doc.text('Dibuat: ' + fdate(new Date().toISOString()), pBX + 5, 28.5)

  y = 48

  // ===== SUMMARY CARDS =====
  sectionTitle('Ringkasan Periode')

  const cards = [
    { label: 'Total Produk', value: `${totalProducts}`, sub: 'produk aktif', bg: C.primaryLight, accent: C.primary },
    { label: 'Nilai Stok', value: rp(totalStockValue), sub: 'estimasi total', bg: C.purpleLight, accent: C.purple },
    { label: 'Barang Masuk', value: `${totalInQty} pcs`, sub: rp(totalInValue), bg: C.emeraldLight, accent: C.emerald },
    { label: 'Barang Keluar', value: `${totalOutQty} pcs`, sub: rp(totalOutValue), bg: C.roseLight, accent: C.rose },
    { label: 'Est. Keuntungan', value: rp(estimasi), sub: estimasi >= 0 ? 'estimasi profit' : 'estimasi rugi', bg: estimasi >= 0 ? C.emeraldLight : C.roseLight, accent: estimasi >= 0 ? C.emerald : C.rose },
  ]

  const cW = (CW - 4 * 2.5) / 5
  cards.forEach((card, i) => {
    const x = M + i * (cW + 2.5)
    dr(x, y, cW, 30, card.bg, 3)
    db(x, y, cW, 30, C.midGray, 0.2, 3)
    dr(x, y, cW, 4, card.accent, 3)
    doc.setFillColor(...card.accent); doc.rect(x, y + 2, cW, 2, 'F')

    sf(6, 'normal', C.gray)
    doc.text(card.label, x + 4, y + 10, { maxWidth: cW - 6 })
    sf(9, 'bold', card.accent)
    doc.text(card.value, x + 4, y + 18, { maxWidth: cW - 6 })
    sf(5.5, 'normal', C.gray)
    doc.text(card.sub, x + 4, y + 25, { maxWidth: cW - 6 })
  })
  y += 36

  // ===== CHART =====
  if (chartLineImg) {
    check(72)
    sectionTitle('Grafik Barang Masuk vs Keluar')
    const chartH = 65
    dr(M, y, CW, chartH, C.white, 3)
    db(M, y, CW, chartH, C.midGray, 0.3, 3)
    doc.addImage(chartLineImg, 'PNG', M + 4, y + 4, CW - 8, chartH - 8)
    y += chartH + 8
  }

  // ===== TOP PRODUCTS =====
  check(55)
  sectionTitle('Produk Terlaris')

  if (topProducts.length === 0) {
    dr(M, y, CW, 16, C.lightGray, 3)
    sf(8, 'normal', C.gray); doc.text('Belum ada data', W / 2, y + 10, { align: 'center' }); y += 20
  } else {
    tableHeader([
      { label: 'No', x: 3 }, { label: 'Nama Produk', x: 14 },
      { label: 'Qty Keluar', x: CW * 0.53 }, { label: 'Nilai', x: CW * 0.67 }, { label: '%', x: CW * 0.84 }
    ])
    topProducts.forEach((p, i) => {
      check(13)
      const rowH = 13
      if (i % 2 === 0) dr(M, y, CW, rowH, C.lightGray)
      db(M, y, CW, rowH, C.midGray, 0.2)

      const rankColors = [C.amber, C.gray, [180, 120, 60], C.midGray, C.midGray]
      const rc = rankColors[i] || C.midGray
      dr(M + 2, y + 3, 9, 7, rc, 2)
      sf(6.5, 'bold', C.white)
      doc.text(`${i + 1}`, M + 6.5, y + 8, { align: 'center' })

      sf(8, 'normal', C.darkGray)
      doc.text(p.name.slice(0, 36), M + 14, y + 8.5)
      sf(8, 'bold', C.rose)
      doc.text(`${p.qty} pcs`, M + CW * 0.53, y + 8.5)
      sf(8, 'normal', C.darkGray)
      doc.text(rp(p.value), M + CW * 0.67, y + 8.5)

      const pct = totalOutAll ? ((p.qty / totalOutAll) * 100).toFixed(1) : 0
      const barX = M + CW * 0.84, barW = CW * 0.11
      dr(barX, y + 5.5, barW, 3, C.midGray, 1.5)
      dr(barX, y + 5.5, Math.max(barW * parseFloat(pct) / 100, 0.5), 3, C.primary, 1.5)
      sf(7, 'normal', C.gray)
      doc.text(`${pct}%`, M + CW * 0.84 + barW + 2, y + 8.5)
      y += rowH
    })
    y += 5
  }

  // ===== REASON SUMMARY =====
  check(55)
  sectionTitle('Ringkasan per Alasan Keluar')

  if (reasonSummary.length === 0) {
    dr(M, y, CW, 16, C.lightGray, 3)
    sf(8, 'normal', C.gray); doc.text('Belum ada data', W / 2, y + 10, { align: 'center' }); y += 20
  } else {
    tableHeader([
      { label: 'Alasan', x: 10 }, { label: 'Qty', x: CW * 0.43 },
      { label: 'Estimasi Nilai', x: CW * 0.57 }, { label: 'Persentase', x: CW * 0.79 }
    ])
    reasonSummary.forEach((r, i) => {
      check(11)
      const rowH = 11
      const rc = REASON_COLORS[r.reason] || C.gray
      if (i % 2 === 0) dr(M, y, CW, rowH, C.lightGray)
      db(M, y, CW, rowH, C.midGray, 0.2)
      doc.setFillColor(...rc)
      doc.circle(M + 5, y + rowH / 2, 2.5, 'F')
      sf(8, 'bold', rc)
      doc.text(r.reason, M + 10, y + rowH / 2 + 2.5)
      sf(8, 'normal', C.darkGray)
      doc.text(`${r.qty} pcs`, M + CW * 0.43, y + rowH / 2 + 2.5)
      doc.text(rp(r.value), M + CW * 0.57, y + rowH / 2 + 2.5)
      const barX = M + CW * 0.79, barW = CW * 0.13
      dr(barX, y + rowH / 2 - 1.5, barW, 3, C.midGray, 1.5)
      dr(barX, y + rowH / 2 - 1.5, Math.max(barW * parseFloat(r.pct) / 100, 0.5), 3, rc, 1.5)
      sf(7, 'normal', C.gray)
      doc.text(`${r.pct}%`, M + CW * 0.79 + barW + 2, y + rowH / 2 + 2.5)
      y += rowH
    })
    dr(M, y, CW, 10, [241, 245, 249])
    db(M, y, CW, 10, C.midGray, 0.3)
    sf(8.5, 'bold', C.darkGray)
    doc.text('Total', M + 10, y + 7)
    doc.text(`${totalOutQty} pcs`, M + CW * 0.43, y + 7)
    doc.text(rp(totalOutValue), M + CW * 0.57, y + 7)
    y += 14
  }

  // ===== INSIGHT =====
  check(38)
  sectionTitle('Insight Cepat')

  const insightDefs = [
    { label: 'Produk Paling Laku', value: topProduct?.name?.slice(0, 22) || 'Belum ada data', sub: topProduct ? `${topProduct.qty} pcs keluar` : '-', color: C.emerald, bg: C.emeraldLight },
    { label: 'Kerugian Terbesar', value: topLoss?.reason || 'Tidak ada kerugian', sub: topLoss ? rp(topLoss.value) : '-', color: C.rose, bg: C.roseLight },
    { label: 'Kategori Terlaris', value: topCat?.[0]?.slice(0, 20) || 'Belum ada data', sub: topCat ? `${topCat[1]} pcs total` : '-', color: C.primary, bg: C.primaryLight },
  ]

  const iW = (CW - 6) / 3
  insightDefs.forEach((ins, i) => {
    const x = M + i * (iW + 3)
    dr(x, y, iW, 30, ins.bg, 3)
    db(x, y, iW, 30, C.midGray, 0.2, 3)
    dr(x, y, iW, 5, ins.color, 3)
    doc.setFillColor(...ins.color); doc.rect(x, y + 3, iW, 2, 'F')

    sf(6.5, 'normal', C.gray)
    doc.text(ins.label, x + 4, y + 12, { maxWidth: iW - 6 })
    sf(9, 'bold', C.darkGray)
    doc.text(ins.value, x + 4, y + 19, { maxWidth: iW - 6 })
    sf(7, 'normal', ins.color)
    doc.text(ins.sub, x + 4, y + 25, { maxWidth: iW - 6 })
  })
  y += 32

  // ===== TRANSACTIONS =====
  check(55)
  sectionTitle('Riwayat Transaksi Terbaru')

  if (combined.length === 0) {
    dr(M, y, CW, 16, C.lightGray, 3)
    sf(8, 'normal', C.gray); doc.text('Belum ada transaksi', W / 2, y + 10, { align: 'center' }); y += 20
  } else {
    tableHeader([
      { label: 'Tanggal', x: 2 }, { label: 'Jenis', x: CW * 0.14 },
      { label: 'Produk', x: CW * 0.31 }, { label: 'Qty', x: CW * 0.63 },
      { label: 'Total', x: CW * 0.76 }, { label: 'Ket.', x: CW * 0.89 }
    ])
    combined.forEach((t, i) => {
      check(12)
      const rowH = 12
      if (i % 2 === 0) dr(M, y, CW, rowH, C.lightGray)
      db(M, y, CW, rowH, C.midGray, 0.2)

      sf(7.5, 'normal', C.gray)
      doc.text(fshort(t.created_at), M + 2, y + rowH / 2 + 2.5)

      const tc = t.type === 'masuk' ? C.emerald : C.rose
      const tBW = 18
      dr(M + CW * 0.14, y + 3, tBW, 6, tc, 3)
      sf(6.5, 'bold', C.white)
      doc.text(t.type === 'masuk' ? 'Masuk' : 'Keluar', M + CW * 0.14 + tBW / 2, y + 7, { align: 'center' })

      sf(8, 'normal', C.darkGray)
      doc.text((t.name || '-').slice(0, 27), M + CW * 0.31, y + rowH / 2 + 2.5)
      sf(8, 'bold', tc)
      doc.text(`${t.type === 'masuk' ? '+' : '-'}${t.qty} ${t.unit}`, M + CW * 0.63, y + rowH / 2 + 2.5)
      sf(8, 'normal', C.darkGray)
      doc.text(rp(t.qty * t.price), M + CW * 0.76, y + rowH / 2 + 2.5)
      sf(7.5, 'normal', C.gray)
      doc.text((t.keterangan || '-').slice(0, 13), M + CW * 0.89, y + rowH / 2 + 2.5)
      y += rowH
    })
  }

  footer()

  const slug = preset === 'month'
    ? new Date().toLocaleDateString('id-ID', { month: 'long', year: 'numeric' }).replace(' ', '-').toLowerCase()
    : preset === 'year' ? new Date().getFullYear()
    : dateFrom || 'semua'
  doc.save(`laporan-simba-${slug}.pdf`)
}